uint8_t ConvertByte(const uint8_t Mass[], uint32_t& v4, uint32_t& IP)
{
	uint8_t Byte = Mass[IP];
	uint8_t Opcode = Mass[IP] ^ v4;

	uint32_t v14 = 0x3C6EF35F + Byte;
	uint32_t v16 = (0x19660D * v4) + v14;
	uint32_t v18 = std::rotr(v16, 29);

	v4 = v18 ^ 0xA5A55A5A;
	IP++;

	return Opcode;
}

uint32_t ConvertDword(const uint8_t Mass[], uint32_t& v4, uint32_t& IP)
{
	uint32_t Result = 0;

	uint8_t OnByte[] = {
		ConvertByte(Mass, v4, IP),
		ConvertByte(Mass, v4, IP),
		ConvertByte(Mass, v4, IP),
		ConvertByte(Mass, v4, IP)
	};

	return	OnByte[3] << 24 | 
			OnByte[2] << 16 |
			OnByte[1] << 8 | 
			OnByte[0];
}

void FindCorectSymbol(uint32_t FirstNum, uint32_t SecondNum, uint32_t ROL,  uint32_t CheckRes)
{
	// ROL( (БУКВА ^ 0x7913A2E1) * 0x045D9F3B, 3 ) == 0x90894968
	for (int i = 0; i < 126; ++i)
	{
		uint32_t Ch = i;
		Ch ^= FirstNum;
		Ch *= SecondNum;
		Ch = std::rotl(Ch, ROL);

		if (Ch == CheckRes)
		{
			std::cout << (char)i;
			break;
		}
	}
}
	
